POST /webhook/checkout-abandoned
Body: { customer_email, product_name, product_price, cart_value, creator_name, creator_niche }
O5: Content-to-Commerce Attribution (20-35% revenue increase)

parameters.jsCode:
// ════════════════════════════════════════════
// CreatorIQ — Generate Recovery Email Content
// AI-crafted personalised recovery email
// In production: call Claude API for dynamic generation
// For POC: uses template logic
// ════════════════════════════════════════════

const d = $input.first().json;
const discountPct = 10;
const discountAmt = Math.round(d.cart_value * discountPct / 100);
const finalPrice  = d.cart_value - discountAmt;

const email = {
  to:       d.customer_email,
  subject:  `🛒 You left something behind — ${d.product_name}`,
  preview:  `Complete your purchase and save $${discountAmt} today only`,

  html_body: `
    <h2>Hey there!</h2>
    <p>You were so close! Your cart from <strong>${d.creator_name}</strong> is waiting.</p>
    <p>You left behind: <strong>${d.product_name}</strong></p>
    <p>For the next 24 hours, use this exclusive code to save ${discountPct}%:</p>
    <h3 style="color:#e74c3c">COMEBACK${discountPct}</h3>
    <p>Original price: $${d.cart_value} → <strong>Your price: $${finalPrice}</strong></p>
    <p>This offer expires in 24 hours.</p>
    <p>Warm regards,<br/>${d.creator_name}</p>
  `,

  metadata: {
    recovery_id:   d.recovery_id,
    discount_code: `COMEBACK${discountPct}`,
    discount_amt:  discountAmt,
    final_price:   finalPrice,
    expires_at:    new Date(Date.now() + 24*60*60*1000).toISOString(),
    workflow:      'O5 — Abandoned Checkout Recovery',
    estimated_recovery_value: finalPrice
  }
};

return [{ json: { ...d, email } }];
